use strict;
use warnings;
use PDF::API2;
use PDF::Text::Simple;

sub extract_info {
    my ($pdf_file) = @_;
    my $pdf = PDF::API2::open($pdf_file);
    my $text = PDF::Text::Simple->new($pdf_file);

    # Extraction de l'auteur
    my $author = $text->author;
    print "L'auteur est : $author\n";

    # Extraction de la date
    my $date = $text->date;
    print "La date est : $date\n";

    # Extraction des tableaux
    my $content = $text->content;
    if ($content =~ /Tableau/){
        print "Il y a mention de tableaux dans le PDF.\n";
    } else {
        print "Aucun tableau trouvé.\n";
    }
}

extract_info('mon_fichier.pdf');
